Object.entries(pageSupplements).forEach(([locale, entries]) => {
    messages[locale] = { ...messages[locale], ...entries };
});

export function useLineWattI18n() {
    const page = usePage();
    const user = computed(() => (page.props as any).auth?.user ?? null);
    const rawLocale = computed(() => String(user.value?.preferred_locale || (page.props as any).locale || 'en'));
    const isTranslatedSurface = computed(() => translatedRoles.has(String(user.value?.role || '')));
    const locale = computed(() => (isTranslatedSurface.value && messages[rawLocale.value] ? rawLocale.value : 'en'));
    const dir = computed(() => (locale.value === 'ar' ? 'rtl' : 'ltr'));
    const supportedLocales = computed<Record<string, string>>(() => (page.props as any).supported_locales || {
        en: 'English',
        de: 'Deutsch',
        fr: 'Français',
        es: 'Español',
        ar: 'العربية',
        pt: 'Português',
        zh: '中文',
        ja: '日本語',
    });

    function t(key: keyof typeof messages.en): string {
        return messages[locale.value]?.[key] || messages.en[key] || key;
    }

    return { locale, dir, supportedLocales, t };
}
